# Create a sign-up/sign-in user flow in the External ID tenant
# User flows are called 'authenticationEventsFlows' in Graph v1.0
$flowBody = @{
    '@odata.type' = '#microsoft.graph.externalUsersSelfServiceSignUpEventsFlow'
    displayName = 'CustomerSignUpSignIn'
    description = 'Default CIAM sign-up and sign-in flow'
    priority = 500
    conditions = @{
        applications = @{
            includeAllApplications = $false
            includeApplications = @(
                @{ appId = 'your-app-client-id' }
            )
        }
    }
    onInteractiveAuthFlowStart = @{
        '@odata.type' = '#microsoft.graph.graphOnInteractiveAuthFlowReadyHandler'
        isSignUpAllowed = $true
    }
    onAuthenticationMethodLoadStart = @{
        '@odata.type' = '#microsoft.graph.graphOnAuthenticationMethodLoadStartHandler'
        identityProviders = @(
            @{ id = 'EmailPassword-OAUTH2-v2' }
            @{ id = 'Email_OTP-OAUTH2-v2' }
        )
    }
    onAttributeCollection = @{
        '@odata.type' = '#microsoft.graph.graphOnAttributeCollectionHandler'
        accessPackage = $null
        attributes = @(
            @{ id = 'email'; isOptional = $false; requiresVerification = $true }
            @{ id = 'displayName'; isOptional = $false; requiresVerification = $false }
            @{ id = 'country'; isOptional = $true; requiresVerification = $false }
        )
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method POST \
    -Uri 'https://graph.microsoft.com/v1.0/identity/authenticationEventsFlows' \
    -Body $flowBody -ContentType 'application/json'

# Register an API connector for a pre-attribute-collection hook in the user flow
# The connector is called BEFORE the sign-up form is shown to validate the email domain
$connector = @{
    displayName        = 'Validate Email Domain'
    targetUrl          = 'https://myfunctions.azurewebsites.net/api/ValidateDomain'
    authenticationConfiguration = @{
        '@odata.type' = '#microsoft.graph.basicAuthentication'
        username      = 'api-connector-user'
        password      = $env:API_CONNECTOR_SECRET
    }
} | ConvertTo-Json -Depth 5

$conn = Invoke-MgGraphRequest -Method POST \
    -Uri 'https://graph.microsoft.com/v1.0/identity/apiConnectors' \
    -Body $connector -ContentType 'application/json'
Write-Host "API connector registered: $($conn.id)"

# Expected response from the connector function (Azure Function example):
# {
#   'version': '1.0.0',
#   'action': 'Continue'    # or 'ShowBlockPage' to deny sign-up
# }

# To block a sign-up based on domain:
# {
#   'version': '1.0.0',
#   'action': 'ShowBlockPage',
#   'userMessage': 'Only corporate emails are allowed to sign up.'
# }

# Enable MFA for customer accounts using TOTP / OATH tokens
# External ID supports: Email OTP (built-in), TOTP apps (Authenticator, Authy)

# Update the user flow to require MFA after initial sign-in
$flowId = "aaaabbbb-flow-id-1234"
$mfaBody = @{
    onUserCreateStart = @{
        '@odata.type' = '#microsoft.graph.graphOnUserCreateStartHandler'
        userTypeToCreate = 'member'
    }
    onMfaMethodLoadStart = @{
        '@odata.type' = '#microsoft.graph.onMfaMethodLoadStartHandler'
        allowedMethods = @('microsoftAuthenticatorPush', 'email')
    }
} | ConvertTo-Json -Depth 5

Invoke-MgGraphRequest -Method PATCH \
    -Uri "https://graph.microsoft.com/v1.0/identity/authenticationEventsFlows/$flowId" \
    -Body $mfaBody -ContentType 'application/json'
Write-Host 'MFA enabled in user flow'

# Customize token claims returned to your app
# Add custom attributes and optional claims to the ID token / access token

# Create an optional claims policy
$claimsPolicy = @{
    displayName = 'CustomerAppClaimsPolicy'
    includeBasicClaimSet = $true
    claimsSchema = @(
        @{
            id             = 'loyaltyTier'
            samlClaimType  = 'http://schemas.microsoft.com/ws/2008/06/identity/claims/extension_LoyaltyTier'
            jwtClaimType   = 'extension_LoyaltyTier'
            valueType      = 'string'
            valueReference = @{ claimValueType = 'userAttribute'; attribute = 'extension_<appId>_LoyaltyTier' }
        }
        @{
            id             = 'country'
            jwtClaimType   = 'country'
            samlClaimType  = 'http://schemas.microsoft.com/ws/2008/06/identity/claims/country'
            valueType      = 'string'
            valueReference = @{ claimValueType = 'userAttribute'; attribute = 'country' }
        }
    )
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method POST \
    -Uri 'https://graph.microsoft.com/beta/trustFramework/policies' \
    -Body $claimsPolicy -ContentType 'application/json'

# Bulk-create customer accounts (migration from legacy IdP)
# Use Graph API to pre-create users with temporary passwords
$legacyUsers = Import-Csv -Path ./legacy-customers.csv
# CSV columns: email, displayName, givenName, surname

foreach ($u in $legacyUsers) {
    $tempPwd = [System.Web.Security.Membership]::GeneratePassword(16, 2)
    $userBody = @{
        accountEnabled    = $true
        displayName       = $u.displayName
        givenName         = $u.givenName
        surname           = $u.surname
        mail              = $u.email
        identities        = @(
            @{
                signInType        = 'emailAddress'
                issuer            = 'your-ciam-tenant.onmicrosoft.com'
                issuerAssignedId  = $u.email
            }
        )
        passwordProfile   = @{
            password                     = $tempPwd
            forceChangePasswordNextSignIn = $true
        }
        passwordPolicies  = 'DisablePasswordExpiration'
    } | ConvertTo-Json -Depth 5

    try {
        $result = Invoke-MgGraphRequest -Method POST \
            -Uri 'https://graph.microsoft.com/v1.0/users' \
            -Body $userBody -ContentType 'application/json'
        Write-Host "Created: $($u.email)"
    } catch {
        Write-Warning "Failed: $($u.email) — $($_.Exception.Message)"
    }
}
